const input = $input.item.json;

// Break the date from "YYYY-MM-DD" to "DD/MM/YYYY"
const [ano, mes, dia] = input.data_agendada.split("-");
const dataFormatada = `${dia}/${mes}/${ano}`;

// Trim the time "HH:MM:SS" to "HH:MM"
const horarioFormatado = input.horario.slice(0, 5);

// Formatted message
const mensagem = `Hello ${input.nome},

This is a reminder that tomorrow we have our appointment at the dealership for a test drive of the ${input.veiculo}.

*Date:* ${dataFormatada}
*Time:* ${horarioFormatado}
*Vehicle:* ${input.veiculo}
*Consultant:* ${input.vendedor}

If you have any questions, we are here to help.

The Dealership`;

return [
  {
    json: {
      telefone: input.telefone,
      mensagem
    }
  }
];

// Generate a random number between 1 and 2
const numeroAleatorio = Math.floor(Math.random() * 2) + 1;

return [
  {
    json: {
      numero: numeroAleatorio
    }
  }
];

const input = $input.item.json;
const dataehora = input.dataehora;

if (!dataehora) {
  throw new Error("Parameter 'dataehora' not provided.");
}

// Convert to Date object
const date = new Date(dataehora);

// Format the date as ISO with a fixed -03:00 offset
function formatToSaoPaulo(date) {
  const pad = n => String(n).padStart(2, '0');

  const year = date.getFullYear();
  const month = pad(date.getMonth() + 1);
  const day = pad(date.getDate());
  const hours = pad(date.getHours());
  const minutes = pad(date.getMinutes());
  const seconds = pad(date.getSeconds());

  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}-03:00`;
}

// Compute start and end with a 30-minute window
const startDate = date;
const finishDate = new Date(date.getTime() + 30 * 60000);

return [
  {
    json: {
      data_start: formatToSaoPaulo(startDate),
      data_finish: formatToSaoPaulo(finishDate)
    }
  }
];

// Read all input data
const inputs = $input.all();

// Check whether there is any data
if (inputs.length === 0) {
  return [{ json: { mensagem: "No data received." } }];
}

// Return only the last item received
const ultimo = inputs[inputs.length - 1];
return [ultimo];

